const inp = $input.first().json;

function b64(str) { return Buffer.from(str, 'utf-8').toString('base64'); }
function pad(n)   { return String(n).padStart(2,'0'); }

const src  = inp.course_id        || 'unknown_src';
const tgt  = inp.target_course_id || 'unknown_tgt';
const sl   = inp.source_language  || 'fr';
const tl   = (inp.target_language || 'en-US').split('-')[0];
const dir  = `${sl}>${tl}`;
const now  = new Date();
const date = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const base = `07_runs/${src}/output`;

// 1. Final HTML
const htmlContent = inp.final_html || '';
const htmlPath    = `${base}/${tgt}_localized_${dir}.html`;
const htmlB64     = b64(htmlContent);

// 2. Decision log
const logObj = {
  meta: { course_id: src, target_course_id: tgt, direction: dir, date, score_total: inp.score_total || null },
  a4_swap_log:       inp.a4_swap_log   || [],
  a5_qa_report:      inp.a5_qa_report  || {},
  a6_issue_log:      inp.a6_issue_log  || [],
  structural_checks: inp.structural_checks || []
};
const logPath = `${base}/${tgt}_decision_log_${dir}.json`;
const logB64  = b64(JSON.stringify(logObj, null, 2));

// 3. TM patch CSV
const tmEntries = inp.domain_tm_patch || [];
let csvTM = 'source_term,target_term,direction,domain,category,context_note,do_not_translate,validated,first_seen_course,last_updated\n';
for (const e of tmEntries) {
  csvTM += [
    e.source_term||'', e.target_term||'', dir,
    e.domain||inp.detected_domain||'', e.category||'',
    (e.context_note||'').replace(/,/g,'；'),
    e.do_not_translate||false, 'false', src, date
  ].join(',') + '\n';
}
const tmPath = `${base}/${tgt}_tm_patch_${dir}.csv`;
const tmB64  = b64(csvTM);

// 4. Pending Phase 2 — collect from all A5 QA reports across chunks
const pending = inp.pending_phase2 || [];
const byType = { static_graphic: [], oc_course_link: [], video: [], external_link: [] };
for (const item of pending) {
  const t = item.type || 'external_link';
  if (byType[t]) byType[t].push(item);
}

// CSV header
const csvHeader = 'type,chapter_index,chunk_index,location,source_value,anchor_text,action_required\n';
function itemToRow(item) {
  return [
    item.type||'', item.chapter_index||0, item.chunk_index||0,
    (item.location||'').replace(/,/g,'；'),
    (item.source_value||'').replace(/,/g,'；'),
    (item.anchor_text||'').replace(/,/g,'；'),
    (item.action_required||'').replace(/,/g,'；')
  ].join(',');
}

// 4a. Static graphics CSV
const csvGraphics = csvHeader + byType.static_graphic.map(itemToRow).join('\n');
const graphicsPath = `${base}/${tgt}_todo_static_graphics_${dir}.csv`;
const graphicsB64  = b64(csvGraphics);

// 4b. External links CSV (OC course links + external links)
const linksItems = [...byType.oc_course_link, ...byType.external_link];
const csvLinks = csvHeader + linksItems.map(itemToRow).join('\n');
const linksPath = `${base}/${tgt}_todo_external_links_${dir}.csv`;
const linksB64  = b64(csvLinks);

// 4c. Videos CSV
const csvVideos = csvHeader + byType.video.map(itemToRow).join('\n');
const videosPath = `${base}/${tgt}_todo_videos_${dir}.csv`;
const videosB64  = b64(csvVideos);

// 5. Review Markdown with ToDo section
const qaScore = inp.score_total ? `${inp.score_total}/100` : 'N/A';
const struct  = inp.structural_integrity ? '✅ OK' : '❌ BLOCKED';
const a6Issues = (inp.a6_issue_log || [])
  .map(i => `- **[${i.severity}]** \`${i.location || 'unknown'}\`: ${i.issue}`)
  .join('\n') || 'None.';

// ToDo table
function todoTable(items, cols) {
  if (!items.length) return '_None detected._';
  const header = '| ' + cols.join(' | ') + ' |';
  const sep    = '| ' + cols.map(() => '---').join(' | ') + ' |';
  const rows   = items.map(item =>
    '| ' + cols.map(c => (String(item[c] || '')).replace(/\|/g,'\\|').slice(0,80)) .join(' | ') + ' |'
  );
  return [header, sep, ...rows].join('\n');
}

const mdContent = `# Course Localization Review — ${tgt}

| Field | Value |
|---|---|
| Source ID | \`${src}\` |
| Target ID | \`${tgt}\` |
| Direction | ${dir} |
| Date | ${date} |
| QA Score | ${qaScore} |
| Structural integrity | ${struct} |

## GitHub Outputs

- [Localized HTML](https://github.com/jeremieborrotzu-blip/Ressources_Loc_OSS/blob/main/${htmlPath})
- [Decision Log](https://github.com/jeremieborrotzu-blip/Ressources_Loc_OSS/blob/main/${logPath})
- [TM Patch](https://github.com/jeremieborrotzu-blip/Ressources_Loc_OSS/blob/main/${tmPath})

## A5 QA Summary

${inp.a5_summary || 'No QA summary available.'}

## A6 Issues

${a6Issues}

---

## Reste à faire — Phase 2

### 🖼 Static Graphics (pending A8 — Image Localizer)

${todoTable(byType.static_graphic, ['location','source_value','anchor_text','action_required'])}

→ [Full CSV](https://github.com/jeremieborrotzu-blip/Ressources_Loc_OSS/blob/main/${graphicsPath})

### 🔗 External Links & OC Course Links

${todoTable(linksItems, ['type','location','source_value','anchor_text','action_required'])}

→ [Full CSV](https://github.com/jeremieborrotzu-blip/Ressources_Loc_OSS/blob/main/${linksPath})

### 🎬 Videos (pending A7 — AV & Caption)

${todoTable(byType.video, ['location','source_value','action_required'])}

→ [Full CSV](https://github.com/jeremieborrotzu-blip/Ressources_Loc_OSS/blob/main/${videosPath})

---

## Localized Content (HTML mirror)

${htmlContent || '<!-- no HTML content -->'}
`;

